parameters.jsonBody:
={
  "model": "solar-pro3",
  "messages": [
    {
      "role": "system",
      "content": "너는 VeriWay 배리어프리 이동경로 추천 서비스의 입력 분석 AI다. 사용자의 자연어 문장에서 출발지, 목적지, 이동 상태, 피해야 할 요소, 필요한 편의시설을 추출한다. 반드시 JSON만 출력한다. 마크다운 코드블록, 설명 문장, 주석은 절대 출력하지 않는다. 출력 형식은 {\"start\":\"\", \"destination\":\"\", \"mobility_condition\":\"\", \"avoid\":[], \"needs\":[], \"user_type\":\"\", \"missing_info\":[], \"confidence\":\"\"} 이다. 출발지가 없으면 start는 빈 문자열로 두고 missing_info에 \"출발지\"를 넣는다. 목적지가 없으면 destination은 빈 문자열로 두고 missing_info에 \"목적지\"를 넣는다. 사용자가 목발, 휠체어, 유모차, 캐리어, 부상, 노약자, 임산부 중 하나를 언급하면 mobility_condition에 반영한다. 목발, 휠체어, 유모차, 캐리어 사용자는 계단을 피해야 하므로 avoid에 \"계단\"을 넣는다. 필요한 시설에는 엘리베이터, 경사로, 평탄한 보도, 장애인 화장실 중 필요한 항목을 넣는다."
    },
    {
      "role": "user",
      "content": "{{ $json.cleaned_input }}"
    }
  ],
  "stream": false
}

parameters.jsCode:
const content = $json.choices?.[0]?.message?.content || "";

let parsed;

try {
  parsed = JSON.parse(content);
} catch (error) {
  parsed = {
    start: "",
    destination: "",
    mobility_condition: "",
    avoid: [],
    needs: [],
    user_type: "",
    missing_info: ["응답 형식 오류"],
    confidence: "low",
    parse_error: true,
    raw_response: content
  };
}

return [
  {
    json: parsed
  }
];

const input = $json.chatInput || "";

const cleanedInput = input
  .trim()
  .replace(/\s+/g, " ")
  .replace(/[ㅠㅜㅋㅎ]+/g, "");

return [
  {
    json: {
      original_input: input,
      cleaned_input: cleanedInput
    }
  }
];

const user = $('JSON_Parse_Check').first().json;
const routes = $input.all().map(item => item.json);

const toBool = (value) => {
  if (typeof value === "boolean") return value;
  if (typeof value === "string") return value.trim().toLowerCase() === "true";
  return false;
};

const normalize = (value) => {
  return String(value || "")
    .trim()
    .replace(/\s+/g, "")
    .replace(/까지|에서|으로|로|가는길|가는/g, "");
};

const userStart = normalize(user.start);
const userDestination = normalize(user.destination);
const mobility = String(user.mobility_condition || "").trim();
const avoid = Array.isArray(user.avoid) ? user.avoid : [];

const matchedRoutes = routes.filter(route => {
  const routeStart = normalize(route.start);
  const routeDestination = normalize(route.destination);

  const sameStart =
    routeStart === userStart ||
    routeStart.includes(userStart) ||
    userStart.includes(routeStart);

  const sameDestination =
    routeDestination === userDestination ||
    routeDestination.includes(userDestination) ||
    userDestination.includes(routeDestination);

  const hasStairs = toBool(route.has_stairs);
  const wheelchairOk = toBool(route.wheelchair_ok);
  const crutchOk = toBool(route.crutch_ok);
  const carrierOk = toBool(route.carrier_ok);
  const strollerOk = toBool(route.stroller_ok);

  let mobilityOk = true;

  if (mobility.includes("휠체어")) mobilityOk = wheelchairOk;
  if (mobility.includes("목발") || mobility.includes("발목") || mobility.includes("부상")) mobilityOk = crutchOk;
  if (mobility.includes("캐리어") || mobility.includes("짐")) mobilityOk = carrierOk;
  if (mobility.includes("유모차")) mobilityOk = strollerOk;

  const avoidStairs = avoid.includes("계단") || mobility.includes("목발") || mobility.includes("휠체어");
  const stairOk = avoidStairs ? hasStairs === false : true;

  return sameStart && sameDestination && mobilityOk && stairOk;
});

return [
  {
    json: {
      ...user,
      debug: {
        user_start_raw: user.start,
        user_destination_raw: user.destination,
        user_start_normalized: userStart,
        user_destination_normalized: userDestination,
        route_count: routes.length,
        sheet_starts: routes.map(r => r.start),
        sheet_destinations: routes.map(r => r.destination)
      },
      matched_routes: matchedRoutes,
      has_route: matchedRoutes.length > 0
    }
  }
];
